@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (!string.IsNullOrEmpty(Title))
    {
        <p class="@TitleClass">@Title</p>
    }
    <div class="flex items-baseline gap-1">
        @if (Prefix is not null)
        {
            <span class="@ValueClass">@Prefix</span>
        }
        <span class="@ValueClass">@ValueBody</span>
        @if (Suffix is not null)
        {
            <span class="@SuffixClass">@Suffix</span>
        }
    </div>
    @if (ShowTrend)
    {
        <div class="mt-1 flex items-center gap-1 text-sm @TrendClasses" aria-label="@TrendAriaLabel">
            @if (TrendDirection == TrendType.Up)
            {
                <SvgGlyph Svg="@(LumeoIcons.TrendingUp)" class="h-4 w-4" aria-hidden="true" />
            }
            else
            {
                <SvgGlyph Svg="@(LumeoIcons.TrendingDown)" class="h-4 w-4" aria-hidden="true" />
            }
            @if (!string.IsNullOrEmpty(TrendValue))
            {
                <span>@TrendValue</span>
            }
        </div>
    }
</div>

@code {
    /// <summary>Label shown above the value, in muted/secondary styling. Hidden when
    /// null/empty.</summary>
    [Parameter] public string? Title { get; set; }

    /// <summary>The raw value to display, as a string. Formatted per <see cref="Precision"/>
    /// and <see cref="Culture"/> when parseable as a number. Overridden by <see cref="ValueContent"/>
    /// when set.</summary>
    [Parameter] public string? Value { get; set; }
    /// <summary>
    /// Custom value content — overrides <see cref="Value"/>. Drop in a
    /// <c>&lt;NumberTicker&gt;</c> (Lumeo.Motion) here for an animated count-up,
    /// rather than duplicating animation logic in core. (#273)
    /// </summary>
    [Parameter] public RenderFragment? ValueContent { get; set; }

    /// <summary>Content rendered immediately before the value (e.g. a currency symbol
    /// or icon), styled at the same size as the value.</summary>
    [Parameter] public RenderFragment? Prefix { get; set; }

    /// <summary>Content rendered immediately after the value (e.g. a unit label),
    /// styled at the muted, smaller caption size.</summary>
    [Parameter] public RenderFragment? Suffix { get; set; }

    /// <summary>Number of decimal places to format <see cref="Value"/> to, when it
    /// parses as a number. Unset (null) renders <see cref="Value"/> verbatim.</summary>
    [Parameter] public int? Precision { get; set; }

    /// <summary>
    /// Culture used when <see cref="Precision"/> is set. Default (null) falls back to
    /// <see cref="System.Globalization.CultureInfo.CurrentCulture"/> so a <c>de-DE</c>
    /// user sees <c>12,34</c> and an <c>en-US</c> user sees <c>12.34</c> automatically.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;

    /// <summary>Shows a trend indicator (up/down arrow plus optional <see cref="TrendValue"/>)
    /// below the value.</summary>
    [Parameter] public bool ShowTrend { get; set; }

    /// <summary>Text shown next to the trend arrow (e.g. <c>"+12%"</c>). When empty,
    /// an accessible "Trending up"/"Trending down" label is synthesized instead since
    /// the arrow icon alone is decorative.</summary>
    [Parameter] public string? TrendValue { get; set; }

    /// <summary>Direction of the trend indicator: Up (success color, default) or
    /// Down (destructive color).</summary>
    [Parameter] public TrendType TrendDirection { get; set; } = TrendType.Up;

    /// <summary>Controls the title/value/suffix text sizes (Sm, Md default, Lg).</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;

    /// <summary>Visual chrome: Default/Minimal (no decoration) or Bordered (rounded
    /// border + padding card wrapper).</summary>
    [Parameter] public StatisticVariant Variant { get; set; } = StatisticVariant.Default;

    /// <summary>Additional CSS classes merged onto the outer wrapper.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures unmatched attributes and applies them to the outer wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private RenderFragment ValueBody => builder =>
    {
        if (ValueContent is not null) builder.AddContent(0, ValueContent);
        else builder.AddContent(1, FormattedValue);
    };

    private string CssClass => Cx.Merge(VariantClass, Class);

    private string VariantClass => Variant switch
    {
        StatisticVariant.Minimal => "",
        StatisticVariant.Bordered => "rounded-lg border border-border/60 p-4",
        _ => ""
    };

    private string TitleClass => Size switch
    {
        Lumeo.Size.Sm => "text-xs text-muted-foreground",
        Lumeo.Size.Lg => "text-base text-muted-foreground",
        _ => "text-sm text-muted-foreground"
    };

    private string ValueClass => Size switch
    {
        Lumeo.Size.Sm => "text-lg font-semibold text-foreground",
        Lumeo.Size.Lg => "text-4xl font-semibold text-foreground",
        _ => "text-2xl font-semibold text-foreground"
    };

    private string SuffixClass => Size switch
    {
        Lumeo.Size.Sm => "text-xs text-muted-foreground",
        Lumeo.Size.Lg => "text-base text-muted-foreground",
        _ => "text-sm text-muted-foreground"
    };

    private const System.Globalization.NumberStyles ParseStyles =
        System.Globalization.NumberStyles.Float | System.Globalization.NumberStyles.AllowThousands;

    private string FormattedValue
    {
        get
        {
            if (Value is null) return "";
            if (Precision.HasValue)
            {
                // Parse order (the old invariant-FIRST + NumberStyles.Any order read
                // de-DE "1234,5" as 12345 — ',' taken as an invariant group separator):
                //
                // 1. When the string contains exactly one '.' and no ',' it is treated
                //    as an invariant decimal ("1234.5" stays 1234.5 even under de-DE,
                //    where a culture-first parse would read '.' as grouping → 12345).
                //    Trade-off, documented: a de-DE group-only string like "1.234"
                //    therefore parses as 1.234, not 1234.
                // 2. Otherwise the component's EffectiveCulture wins (de-DE "1234,5"
                //    → 1234.5; "1.234,56" → 1234.56).
                // 3. Invariant as the last-resort fallback.
                //
                // Render via the effective culture so separators match the locale.
                var looksInvariantDecimal =
                    Value.Count(ch => ch == '.') == 1 && !Value.Contains(',');

                if (looksInvariantDecimal
                    && double.TryParse(Value, ParseStyles, System.Globalization.CultureInfo.InvariantCulture, out var numericValue))
                {
                    return numericValue.ToString($"N{Precision.Value}", EffectiveCulture);
                }

                if (double.TryParse(Value, ParseStyles, EffectiveCulture, out numericValue)
                    || double.TryParse(Value, ParseStyles, System.Globalization.CultureInfo.InvariantCulture, out numericValue))
                {
                    return numericValue.ToString($"N{Precision.Value}", EffectiveCulture);
                }
            }
            return Value;
        }
    }

    private string TrendClasses => TrendDirection switch
    {
        TrendType.Up => "text-success",
        TrendType.Down => "text-destructive",
        _ => ""
    };

    // The directional icon is decorative (aria-hidden), so when there is no
    // visible TrendValue text the trend container would have no accessible name.
    // Supply a direction label in that case; when TrendValue is present its text
    // already names the container, so leave it null (attribute omitted).
    private string? TrendAriaLabel => string.IsNullOrEmpty(TrendValue)
        ? (TrendDirection == TrendType.Up ? "Trending up" : "Trending down")
        : null;

    public enum TrendType { Up, Down }
    /// <summary>
    /// Default = plain (no decoration). Minimal = alias for Default (explicit opt-in to no chrome).
    /// Bordered = rounded border card wrapper.
    /// </summary>
    public enum StatisticVariant { Default, Minimal, Bordered }
}
